import java.io.IOException;
import java.net.HttpURLConnection;
import java.net.URL;

import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;

public class IoTDeviceManagerClient {

    private static final String BASE_URL_LOCAL = "http://192.168.x.x/";
    private static final String BASE_URL_CLOUD = "your_cloud_api_url.com/";

    private OkHttpClient okHttpClient = new OkHttpClient();

    public String sendCommand(String deviceName, String command) throws IOException {
        String localUrl = BASE_URL_LOCAL + deviceName + "/command/" + command;
        String cloudUrl = BASE_URL_CLOUD + deviceName + "/command/" + command;

        String response = sendRequest(localUrl);
        if (response == null) {
            response = sendRequest(cloudUrl);
        }

        return response;
    }

    private String sendRequest(String url) throws IOException {
        Request request = new Request.Builder().url(url).build();
        Response response = okHttpClient.newCall(request).execute();

        if (response.isSuccessful()) {
            return response.body().string();
        } else {
            throw new IOException("Request failed: " + response.message());
        }
    }
}